svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
    var dataLayerEl = svgEl.querySelector('.data-layer');

    /* Position tooltip bubbles via getBBox(); CSS owns show/hide */
    function initBubbles() {
      var tipLayerEl = svgEl.querySelector('#tip-layer');
      var TAIL = 14, tw = 10, rx = 12;
      var barHW = 32;  /* half of bar width=64 */
      var bh = 200;
      var plotL = 42, plotR = 840, plotT = 100, plotB = 500;

      ctx.$$all('.data-item').forEach(function (dataItem) {
        var itemCx  = parseFloat(dataItem.getAttribute('data-item-cx'));
        var itemTop = parseFloat(dataItem.getAttribute('data-item-top'));
        var tip = dataItem.querySelector('.data-tip');
        var texts = tip.querySelectorAll('text');
        var bgRect = tip.querySelector('rect');
        var paths  = tip.querySelectorAll('path');
        var bdrPath = paths[0], tlPath = paths[1];

        /* measure text at origin */
        Array.prototype.forEach.call(texts, function (t) {
          t.setAttribute('x', '0'); t.setAttribute('y', '0');
        });
        var bw = Math.max(
          texts[0].getBBox().width + 40,
          texts[1].getBBox().width + 40,
          220
        );

        /* horizontal: go whichever side has more room */
        var spaceR = plotR - (itemCx + barHW);
        var spaceL = (itemCx - barHW) - plotL;
        var goRight = spaceR >= spaceL;
        var ancX, bL, bR;
        if (goRight) {
          ancX = itemCx + barHW; bL = ancX + TAIL; bR = bL + bw;
        } else {
          ancX = itemCx - barHW; bR = ancX - TAIL; bL = bR - bw;
        }

        /* vertical: center on bar top, clamp to chart */
        var ancY = itemTop;
        var bT = ancY - bh / 2;
        var bB = bT + bh;
        if (bT < plotT) { bT = plotT; bB = bT + bh; }
        if (bB > plotB) { bB = plotB; bT = bB - bh; }
        var tY = Math.max(bT + rx + tw, Math.min(bB - rx - tw, ancY));

        /* open-sided border and tail */
        var op, tp;
        if (goRight) {
          /* gap on left edge */
          op = 'M'+bL+','+(tY-tw)+
               ' L'+bL+','+(bT+rx)+' Q'+bL+','+bT+' '+(bL+rx)+','+bT+
               ' L'+(bR-rx)+','+bT+' Q'+bR+','+bT+' '+bR+','+(bT+rx)+
               ' L'+bR+','+(bB-rx)+' Q'+bR+','+bB+' '+(bR-rx)+','+bB+
               ' L'+(bL+rx)+','+bB+' Q'+bL+','+bB+' '+bL+','+(bB-rx)+
               ' L'+bL+','+(tY+tw);
          tp = 'M'+bL+','+(tY+tw)+' L'+ancX+','+ancY+' L'+bL+','+(tY-tw);
        } else {
          /* gap on right edge */
          op = 'M'+bR+','+(tY+tw)+
               ' L'+bR+','+(bB-rx)+' Q'+bR+','+bB+' '+(bR-rx)+','+bB+
               ' L'+(bL+rx)+','+bB+' Q'+bL+','+bB+' '+bL+','+(bB-rx)+
               ' L'+bL+','+(bT+rx)+' Q'+bL+','+bT+' '+(bL+rx)+','+bT+
               ' L'+(bR-rx)+','+bT+' Q'+bR+','+bT+' '+bR+','+(bT+rx)+
               ' L'+bR+','+(tY-tw);
          tp = 'M'+bR+','+(tY-tw)+' L'+ancX+','+ancY+' L'+bR+','+(tY+tw);
        }

        bgRect.setAttribute('x', String(bL)); bgRect.setAttribute('y', String(bT));
        bgRect.setAttribute('width', String(bw)); bgRect.setAttribute('height', String(bh));
        bgRect.setAttribute('rx', String(rx));
        bdrPath.setAttribute('d', op);
        tlPath.setAttribute('d', tp);
        texts[0].setAttribute('x', String(bL + bw / 2));
        texts[0].setAttribute('y', String(bT + bh * 0.35));
        texts[1].setAttribute('x', String(bL + bw / 2));
        texts[1].setAttribute('y', String(bT + bh * 0.65));
        /* lift tip above all bars */
        tipLayerEl.appendChild(tip);
        dataItem._tip = tip;
      });
    }
    initBubbles();

    /* Hover — data layer dims; tips live in #tip-layer so JS controls opacity directly */
    var dataItemEls = ctx.$$all('.data-item');
    dataItemEls.forEach(function (dataItem) {
      dataItem.addEventListener('mouseenter', function () {
        dataLayerEl.classList.add('hovering');
        dataItemEls.forEach(function (x) {
          x.classList.remove('active');
          if (x._tip) x._tip.style.opacity = '';
        });
        dataItem.classList.add('active');
        if (dataItem._tip) dataItem._tip.style.opacity = '1';
      });
      dataItem.addEventListener('mouseleave', function () {
        dataItem.classList.remove('active');
        if (dataItem._tip) dataItem._tip.style.opacity = '';
        dataLayerEl.classList.remove('hovering');
      });
    });
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
